<script>(function(){var rows=[].slice.call(document.querySelectorAll('#accountantTable tbody tr')),form=document.getElementById('accountantFilterForm'),modal=window.bootstrap?new bootstrap.Modal(document.getElementById('deleteAccountantModal')):null;function n(v){return String(v||'').toLowerCase().trim()}form.addEventListener('submit',function(e){e.preventDefault();var sid=n(staffId.value),nm=n(accountantName.value),dep=departmentFilter.value,st=statusFilter.value;rows.forEach(function(r){r.style.display=(!sid||n(r.dataset.staffId).indexOf(sid)>-1)&&(!nm||n(r.dataset.name).indexOf(nm)>-1)&&(!dep||r.dataset.department===dep)&&(!st||r.dataset.status===st)?'':'none'})});form.addEventListener('reset',function(){setTimeout(function(){rows.forEach(function(r){r.style.display=''})},0)});selectAllAccountants.addEventListener('change',function(){document.querySelectorAll('.accountant-select').forEach(function(c){c.checked=selectAllAccountants.checked})});deleteSelected.addEventListener('click',function(){var c=document.querySelectorAll('.accountant-select:checked').length;if(!c){alert('Please select at least one accountant.');return} if(confirm('Soft delete '+c+' selected accountant record(s)?')) alert('Selected records marked for soft deletion.')});exportCsv.onclick=function(){alert('CSV export placeholder ready for backend integration.')};exportExcel.onclick=function(){alert('Excel export placeholder ready for backend integration.')};printList.onclick=function(){window.print()};document.querySelectorAll('.delete-accountant-btn').forEach(function(b){b.onclick=function(){deleteAccountantId.value=b.dataset.accountantId;deleteStaffId.value=b.dataset.staffId;deleteAccountantName.textContent=b.dataset.name;modal?modal.show():alert('Delete '+b.dataset.name)}});deleteAccountantForm.addEventListener('submit',function(e){e.preventDefault();alert('Accountant record marked for soft deletion. Future endpoint: accountant-delete.php')});})();</script>
